// save_order: insert header (auto doc_no) + items
const body = items[0].json.body;
const now = new Date();
const yy = String(now.getFullYear()).slice(-2);
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const rand = Math.floor(Math.random() * 9000 + 1000);
const docNo = body.doc_no && body.doc_no.trim() ? body.doc_no : `OD${yy}${mm}${dd}${rand}`;
return [{ json: { ...body, doc_no: docNo } }];

// build INSERT for items using returned order_id
const orderId = $items('PG: Insert Order')[0].json.order_id;
const body = $items('Webhook')[0].json.body;
const items = (body.items || []).filter(it => it.part_code || it.part_name);
if (!items.length) return [{ json: { sql: 'SELECT 1;', order_id: orderId, doc_no: $items('PG: Insert Order')[0].json.doc_no } }];
const values = items.map(it => `(${orderId}, '${(it.part_code||'').replace(/'/g,"''")}', '${(it.part_name||'').replace(/'/g,"''")}', ${Number(it.quantity)||1})`).join(',');
const sql = `INSERT INTO outside_deposit_items (order_id, part_code, part_name, quantity) VALUES ${values};`;
return [{ json: { sql, order_id: orderId, doc_no: $items('PG: Insert Order')[0].json.doc_no } }];

// build UPDATE header + DELETE items + INSERT items
const body = $items('Webhook')[0].json.body;
const id = body.order_id;
const esc = s => String(s||'').replace(/'/g,"''");
const items = (body.items||[]).filter(it => it.part_code || it.part_name);
let sql = `UPDATE outside_deposit_orders SET customer_name='${esc(body.customer_name)}', customer_phone='${esc(body.customer_phone)}', license_plate='${esc(body.license_plate)}', job_no='${esc(body.job_no)}', technician='${esc(body.technician)}', model_name='${esc(body.model_name)}', parking_status='${esc(body.parking_status)}', status='${esc(body.status)}', updated_at=NOW() WHERE order_id=${id};`;
sql += ` DELETE FROM outside_deposit_items WHERE order_id=${id};`;
if (items.length) {
  const vals = items.map(it => `(${id}, '${esc(it.part_code)}', '${esc(it.part_name)}', ${Number(it.quantity)||1})`).join(',');
  sql += ` INSERT INTO outside_deposit_items (order_id, part_code, part_name, quantity) VALUES ${vals};`;
}
return [{ json: { sql, order_id: id } }];
